import { useState } from 'react';
import { useForm } from 'react-hook-form';
import axios from 'axios';

interface FormData {
  income: number;
  age: number;
  // ... thêm 8 fields còn lại
}

export default function Apply() {
  const { register, handleSubmit, formState: { errors } } = useForm<FormData>();
  const [result, setResult] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const onSubmit = async (data: FormData) => {
    setLoading(true);
    try {
      const res = await axios.post(process.env.NEXT_PUBLIC_API_URL + '/predict', data);
      setResult(res.data);
    } catch (err) {
      setError('API error');
    }
    setLoading(false);
  };

  return (
    <div className="container mx-auto p-4">
      <h1 className="text-2xl">Apply for Loan</h1>
      <form onSubmit={handleSubmit(onSubmit)} className="grid grid-cols-2 gap-4">
        <input {...register('income', { required: true })} placeholder="Income" type="number" />
        {errors.income && <span>Required</span>}
        {/* Thêm inputs cho các fields khác */}
        <button type="submit" className="bg-blue-500 text-white p-2">Submit</button>
      </form>
      {loading && <p>Loading...</p>}
      {error && <p>Error: {error}</p>}
      {result && (
        <div>
          <p>Score: {result.approval_score}</p>
          <p>Approved: {result.approved ? 'Yes' : 'No'}</p>
          <p>Risk: {result.risk_level}</p>
          <p>Recommendation: {result.recommendation}</p>
        </div>
      )}
    </div>
  );
}
